@app.get("/metadata")
def metadata():
    settings = OneLogin_Saml2_Settings(_settings_dict(), custom_base_path=None)
    xml = settings.get_idp_metadata()
    errors = settings.validate_metadata(xml)
    if errors:
        return make_response("Metadata validation errors: " + ", ".join(errors), 500)
    resp = make_response(xml, 200)
    resp.headers["Content-Type"] = "application/samlmetadata+xml"
    return resp


@app.route("/sso", methods=["GET", "POST"])
def sso():
    saml_request = request.values.get("SAMLRequest", "")
    relay_state = request.values.get("RelayState", DEFAULT_RELAY_STATE)

    user = _get_session_user(request)
    if request.method == "GET":
        if user:
            return _issue_saml_response(user, saml_request, relay_state)
        return render_template_string(LOGIN_FORM_HTML, error=None, saml_request=saml_request, relay_state=relay_state)

    username = (request.form.get("username") or "").strip()
    password = request.form.get("password") or ""
    saml_request = request.form.get("SAMLRequest", saml_request)
    relay_state = request.form.get("RelayState", relay_state)

    if not _authenticate_user(username, password):
        return render_template_string(LOGIN_FORM_HTML, error="Invalid credentials", saml_request=saml_request, relay_state=relay_state), 401

    resp = make_response(_issue_saml_response(username, saml_request, relay_state))
    _set_session_user(resp, username)
    return resp


def _issue_saml_response(username: str, saml_request_b64: str, relay_state: str):
    in_response_to = None
    acs_url = SP_ACS_URL
    audience = SP_ENTITY_ID

    if saml_request_b64:
        try:
            req_data = _prepare_flask_request(request)
            auth = OneLogin_Saml2_Auth(req_data, old_settings=_settings_dict())
            auth.process_sso()
            errors = auth.get_errors()
            if errors:
                abort(400, "Invalid SAMLRequest: " + ", ".join(errors))
            last_request_id = auth.get_last_request_id()
            in_response_to = last_request_id
        except Exception:
            abort(400, "Failed to parse/process SAMLRequest")
    else:
        if not ALLOW_UNSOLICITED:
            abort(400, "Missing SAMLRequest (unsolicited responses disabled)")

    attrs = _user_attributes(username)
    xml, _, _ = _build_response_xml(
        in_response_to=in_response_to,
        acs_url=acs_url,
        audience=audience,
        name_id=username,
        attributes=attrs,
    )
    signed_xml = _sign_assertion_in_response(xml)
    saml_response = _b64encode_xml(signed_xml)

    return render_template_string(
        POST_FORM_TEMPLATE,
        acs_url=acs_url,
        saml_response=saml_response,
        relay_state=relay_state,
    )


@app.get("/logout")
def logout():
    resp = make_response(redirect("/sso"))
    _clear_session_user(resp)
    return resp


